export const darkTheme = {
  '--bg-color': '#0a0a0a',
  '--card-bg': '#141414',
  '--input-bg': 'rgba(0, 0, 0, 0.4)',
  '--primary-accent': '#10b981', // Emerald
  '--text-main': '#f9fafb',
  '--text-muted': '#6b7280',
  '--border-color': 'rgba(255, 255, 255, 0.08)',
  '--card-shadow': '0 20px 40px rgba(0, 0, 0, 0.6)',
};

export const lightTheme = {
  '--bg-color': '#f3f4f6', // Silver Terminal variant
  '--card-bg': '#ffffff',
  '--primary-accent': '#059669',
  '--text-main': '#111827',
  '--border-color': '#e5e7eb',
};
